import{_ as d,W as o,X as i,Z as e,$ as t,a0 as a,a1 as s,D as r}from"./framework-c9619a7b.js";const c={},l=e("h2",{id:"简介",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),t(" 简介")],-1),p=e("p",null,"Dendron是一款面向程序员的知识库软件，它基于文本文件，使用Markdown语言进行格式化，允许用户创建和组织个人知识库，并快速查找和共享这些信息。Dendron的设计理念是将知识组织成树状结构，以便于用户快速定位和理解各个知识点之间的关系。",-1),u=e("figure",null,[e("img",{src:"https://minio.kevin2li.top/image-bed/20230428185627.png",alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h=e("p",null,"Dendron提供了多种功能，包括创建多个笔记本、在笔记中添加文本、代码块、图片等内容、使用标签、链接、目录等功能进行组织和分类、强大的搜索功能以及与其他知识库软件的集成等。",-1),m=e("p",null,"对于程序员来说，Dendron非常适合用于存储和组织代码、API文档、技术博客、笔记等信息。通过使用Dendron，程序员可以更加高效地管理和利用自己的知识库，提高工作效率和代码质量。",-1),k={href:"https://www.dendron.so/",target:"_blank",rel:"noopener noreferrer"},v={href:"https://wiki.dendron.so/",target:"_blank",rel:"noopener noreferrer"},b=s('<h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><blockquote><p>背景：由于Dendron很多功能都没有设置快捷键，使用起来不是很方便，但是可以自己为其指定快捷键。VSCode中指定快捷键的方式可以参考： ![[快捷键设置|Tutorial.VSCode使用教程#查看修改新建删除快捷键]]</p></blockquote><h3 id="note管理" tabindex="-1"><a class="header-anchor" href="#note管理" aria-hidden="true">#</a> note管理</h3><table><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+L</code></td><td>创建/查找note</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+X</code></td><td>重命名note</td></tr><tr><td><code>Ctrl+Shift+D</code></td><td>删除当前note</td></tr><tr><td><code>Ctrl+K Shift+Alt+R</code></td><td>Refactor Hierachy, 把所有文件名中匹配到的部分替换为其他</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+H</code></td><td>Move Header, 把当前note光标下的标题移动到其他note尾部</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+S</code></td><td>Move Selection, 把当前note鼠标选中的部分移动到其他note尾部</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+T</code></td><td>Apply Template, 在当前note中应用模板</td></tr><tr><td><code>Ctrl+K Ctrl+Enter</code></td><td>Go to Note, 跳转到目标note，没有会自动新建</td></tr></tbody></table><p>当创建很长名字的note时，可以先在文档中编辑好，然后光标放在名称上，然后使用<code>Dendron: Go to Note</code>会自动创建。</p><h3 id="link管理" tabindex="-1"><a class="header-anchor" href="#link管理" aria-hidden="true">#</a> link管理</h3><table><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+Shift+C</code></td><td>获取当前激活note的link，插入后只会显示一个超链接。如果在标题处使用则会生成直接指向目标标题的链接</td></tr><tr><td><code>Ctrl+Shift+R</code></td><td>获取当前激活note的reference，插入后会在当前页面显示目标页面</td></tr></tbody></table><ol><li><p>获取note部分内容的link</p></li><li><p>引用note</p></li><li><p>部分引用note</p></li></ol><h3 id="schema管理" tabindex="-1"><a class="header-anchor" href="#schema管理" aria-hidden="true">#</a> schema管理</h3>',9),f={href:"https://wiki.dendron.so/notes/c5e5adde-5459-409b-b34d-a0d75cbb1052/",target:"_blank",rel:"noopener noreferrer"},y=s(`<p>设置<code>schema</code>可以从已有的markdown文件中生成结构和类型提示,在创建新note时可以进行参考,也可以指定应用模板. 其中<code>schema</code>中的<code>id</code>和<code>pattern</code>是会去匹配文件名的属性.</p><h4 id="方式一-childred属性下指定孩子节点的id" tabindex="-1"><a class="header-anchor" href="#方式一-childred属性下指定孩子节点的id" aria-hidden="true">#</a> 方式一: <code>childred</code>属性下指定孩子节点的<code>id</code></h4><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token number">1</span>
<span class="token key atrule">schemas</span><span class="token punctuation">:</span>
<span class="token comment"># this will match &quot;cli.*&quot; notes</span>
<span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> cli 
  <span class="token comment"># human readable description of hierarchy</span>
  <span class="token key atrule">desc</span><span class="token punctuation">:</span> command line interface reference
  <span class="token comment"># add this to the domain of your schema hierarchy</span>
  <span class="token key atrule">parent</span><span class="token punctuation">:</span> root
  <span class="token comment"># when a schema is a namespace, it can have arbitrary children. equivalent to cli.* glob pattern</span>
  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> <span class="token boolean important">true</span> 
  <span class="token key atrule">children</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> cmd
    <span class="token punctuation">-</span> env
<span class="token comment"># will match cli.*.env</span>
<span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> env
  <span class="token key atrule">desc</span><span class="token punctuation">:</span> cli specific env variables
<span class="token comment"># will match cli.*.cmd.*</span>
<span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> cmd
  <span class="token key atrule">desc</span><span class="token punctuation">:</span> subcommands 
  <span class="token key atrule">namespace</span><span class="token punctuation">:</span> <span class="token boolean important">true</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>匹配的结构如下:</p><figure><img src="https://minio.kevin2li.top/image-bed/20230428182504.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h4 id="方式二-推荐-childred属性下指定孩子的pattern" tabindex="-1"><a class="header-anchor" href="#方式二-推荐-childred属性下指定孩子的pattern" aria-hidden="true">#</a> 方式二(推荐): <code>childred</code>属性下指定孩子的<code>pattern</code></h4><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token number">1</span>
<span class="token key atrule">schemas</span><span class="token punctuation">:</span>
  <span class="token comment"># Daily is the top most schema since its parent is &#39;root&#39; it must have an identifier</span>
  <span class="token comment"># this identifier &#39;daily&#39; will be used when using &#39;Lookup (schema)&#39; command.</span>
  <span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> daily
    <span class="token key atrule">parent</span><span class="token punctuation">:</span> root
    <span class="token comment"># Children of the top most schema do not need to contain identifier and just </span>
    <span class="token comment"># require a &#39;pattern&#39; to be set to match the hierarchy of notes.</span>
    <span class="token key atrule">children</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> <span class="token key atrule">pattern</span><span class="token punctuation">:</span> journal
        <span class="token key atrule">children</span><span class="token punctuation">:</span>
          <span class="token punctuation">-</span> <span class="token key atrule">pattern</span><span class="token punctuation">:</span> <span class="token string">&quot;[0-2][0-9][0-9][0-9]&quot;</span>
            <span class="token key atrule">children</span><span class="token punctuation">:</span>
              <span class="token punctuation">-</span> <span class="token key atrule">pattern</span><span class="token punctuation">:</span> <span class="token string">&quot;[0-1][0-9]&quot;</span>
                <span class="token key atrule">children</span><span class="token punctuation">:</span>
                  <span class="token punctuation">-</span> <span class="token key atrule">pattern</span><span class="token punctuation">:</span> <span class="token string">&quot;[0-3][0-9]&quot;</span>
                    <span class="token comment"># As with regular schema we can set the template to be used with</span>
                    <span class="token comment"># the match of our notes. Below is an example usage of shorthand template</span>
                    <span class="token comment"># definition (which defaults to type: note). </span>
                    <span class="token key atrule">template</span><span class="token punctuation">:</span> templates.daily
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>此方式更容易看出层级结构.</p><div class="hint-container tip"><p class="hint-container-title">重建索引</p><p>修改完schema后可能不会立即生效,可以重建索引或者重新加载窗口重试一下.</p><p>重建索引快捷键如下(需要自己设置):</p><p><code>Ctrl+K Ctrl+Shift+R</code>: <code>Dendron: Reload Index</code></p></div><h3 id="模板-template" tabindex="-1"><a class="header-anchor" href="#模板-template" aria-hidden="true">#</a> 模板(Template)</h3><h4 id="方式一-当前页面应用" tabindex="-1"><a class="header-anchor" href="#方式一-当前页面应用" aria-hidden="true">#</a> 方式一: 当前页面应用</h4><p>任意新建一个文件, 一般位于<code>template</code>目录下,然后可以使用<code>Ctrl+K Ctrl+Shift+T</code>在当前页面应用模板</p><h4 id="方式二-与schema绑定自动应用" tabindex="-1"><a class="header-anchor" href="#方式二-与schema绑定自动应用" aria-hidden="true">#</a> 方式二: 与schema绑定自动应用</h4><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token number">1</span>
<span class="token key atrule">schemas</span><span class="token punctuation">:</span>
<span class="token punctuation">-</span> <span class="token key atrule">id</span><span class="token punctuation">:</span> blog
  <span class="token key atrule">title</span><span class="token punctuation">:</span> Blog
  <span class="token key atrule">desc</span><span class="token punctuation">:</span> <span class="token string">&quot;&quot;</span>
  <span class="token key atrule">parent</span><span class="token punctuation">:</span> root
  <span class="token key atrule">children</span><span class="token punctuation">:</span>
    <span class="token punctuation">-</span> <span class="token key atrule">pattern</span><span class="token punctuation">:</span> <span class="token string">&quot;+([!])&quot;</span>
      <span class="token key atrule">template</span><span class="token punctuation">:</span> template.blog
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在与<code>pattern</code>同层级加入<code>template</code>属性来指定应用的模板.</p><p><code>pattern</code>语法:</p><table><thead><tr><th>name</th><th>function</th></tr></thead><tbody><tr><td>&quot;[!0-9]&quot;</td><td>will match anything that&#39;s not a digit</td></tr><tr><td>&quot;*([0-9])&quot;</td><td>will match 0 or more digits</td></tr><tr><td>&quot;+([0-9])&quot;</td><td>will match 1 or more digits</td></tr><tr><td>&quot;*&quot;</td><td>will match 0 or more of any character</td></tr><tr><td>&quot;+([!])&quot;</td><td>will match 1 or more of any character</td></tr><tr><td>&quot;@(left | right)&quot;</td><td>will match left or right, but nothing else</td></tr><tr><td>&quot;!(thing)&quot;</td><td>will match anything other than thing</td></tr></tbody></table><p>模板变量:</p><table><thead><tr><th>name</th><th>function</th></tr></thead><tbody><tr><td><code>CURRENT_YEAR</code></td><td>The current year</td></tr><tr><td><code>CURRENT_MONTH</code></td><td>The month as two digits (example: 02 for February)</td></tr><tr><td><code>CURRENT_WEEK</code></td><td>The week of the year as two digits (example: 17)</td></tr><tr><td><code>CURRENT_DAY</code></td><td>The day of the month as two digits (example: 08)</td></tr><tr><td><code>CURRENT_HOUR</code></td><td>The current hour in 24-hour clock format (example: 23)</td></tr><tr><td><code>CURRENT_MINUTE</code></td><td>The current minute as two digits (example: 05)</td></tr><tr><td><code>CURRENT_SECOND</code></td><td>The current second as two digits (exmplae: 32)</td></tr><tr><td><code>CURRENT_QUARTER</code></td><td>The current quarter as one-indexed single digit number (example: 1 for first quarter)</td></tr><tr><td><code>CURRENT_MONTH_NAME</code></td><td>The month as string name (example: January)</td></tr><tr><td><code>CURRENT_MONTH_NAME_SHORT</code></td><td>The month as abbreviated string name (example: Jan for January)</td></tr><tr><td><code>CURRENT_DAY_OF_WEEK</code></td><td>equivalent of javascript getDay method (example: 3 for Monday)</td></tr><tr><td><code>CURRENT_DAY_OF_WEEK_ABBR</code></td><td>The day of week, as an abbreviated localized string (example: Wed for Wednesday)</td></tr><tr><td><code>CURRENT_DAY_OF_WEEK_FULL</code></td><td>The day of week, as an unabbreviated localized string (example: Wednesday),</td></tr><tr><td><code>CURRENT_DAY_OF_WEEK_SINGLE</code></td><td>(example: W for Wednesday),</td></tr><tr><td><code>TITLE</code></td><td>The title of the note as appeared on frontmatter</td></tr><tr><td><code>FNAME</code></td><td>name of current file</td></tr><tr><td><code>DESC</code></td><td>description of current file (equivalent to the desc field in the Dendron frontmatter)</td></tr></tbody></table><p>可以使用<code>{{ VARIABLE }}</code>在正文中引用变量.</p><h3 id="markdown快捷键" tabindex="-1"><a class="header-anchor" href="#markdown快捷键" aria-hidden="true">#</a> Markdown快捷键</h3>`,21),_={href:"https://marketplace.visualstudio.com/items?itemName=dendron.dendron-markdown-shortcuts",target:"_blank",rel:"noopener noreferrer"},g=s('<table><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+M Ctrl+M</code></td><td>调出常用md格式: <br><img src="https://minio.kevin2li.top/image-bed/20230428180010.png" alt="" loading="lazy"></td></tr></tbody></table><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',2),w={href:"https://wiki.dendron.so/",target:"_blank",rel:"noopener noreferrer"};function C(T,R){const n=r("ExternalLinkIcon");return o(),i("div",null,[l,p,u,h,m,e("p",null,[t("官网: "),e("a",k,[t("https://www.dendron.so/"),a(n)])]),e("p",null,[t("文档: "),e("a",v,[t("https://wiki.dendron.so/"),a(n)])]),b,e("p",null,[t("参考: "),e("a",f,[t("dendron | Schemas"),a(n)])]),y,e("p",null,[t("依赖插件:"),e("a",_,[t("Dendron Markdown Shortcuts"),a(n)])]),g,e("ol",null,[e("li",null,[e("a",w,[t("https://wiki.dendron.so/"),a(n)])])])])}const E=d(c,[["render",C],["__file","Dendron个人知识库工具使用教程.html.vue"]]);export{E as default};
